Use a frequency count after normalizing both strings.

```js
function areAnagrams(a, b) {
  const s1 = a.replace(/\s+/g, '').toLowerCase();
  const s2 = b.replace(/\s+/g, '').toLowerCase();

  if (s1.length !== s2.length) return false;

  const count = new Map();

  for (const ch of s1) {
    count.set(ch, (count.get(ch) || 0) + 1);
  }

  for (const ch of s2) {
    if (!count.has(ch)) return false;
    const next = count.get(ch) - 1;
    if (next === 0) count.delete(ch);
    else count.set(ch, next);
  }

  return count.size === 0;
}
```

Example:

```js
areAnagrams('listen', 'silent'); // true
areAnagrams('hello', 'world');   // false
```

