Use a stack: push `(`, `{`, `[`; on `)`, `}`, `]`, pop and ensure the types match; valid iff you never mismatch and the stack is empty at the end.

```js
function isBalanced(s) {
  const stack = [];
  const pairs = { ')': '(', ']': '[', '}': '{' };

  for (const ch of s) {
    if (ch === '(' || ch === '[' || ch === '{') {
      stack.push(ch);
    } else if (ch === ')' || ch === ']' || ch === '}') {
      if (stack.pop() !== pairs[ch]) return false;
    }
  }

  return stack.length === 0;
}
```

Examples:
