import java.nio.charset.CodingErrorAction;
import java.nio.charset.StandardCharsets;

public static String readUtf8Body(InputStream bodyStream, int maxBytes)
        throws IOException, CharacterCodingException {
    if (maxBytes < 0) {
        throw new IllegalArgumentException("maxBytes must be >= 0");
    }

    ByteArrayOutputStream out = new ByteArrayOutputStream();
    byte[] buffer = new byte[8192];
    int total = 0;
    int read;

    while ((read = bodyStream.read(buffer)) != -1) {
        total += read;
        if (total > maxBytes) {
            throw new IllegalArgumentException("Body exceeds max size of " + maxBytes + " bytes");
        }
        out.write(buffer, 0, read);
    }

    ByteBuffer bytes = ByteBuffer.wrap(out.toByteArray());
    CharBuffer chars = StandardCharsets.UTF_8
            .newDecoder()
            .onMalformedInput(CodingErrorAction.REPORT)
            .onUnmappableCharacter(CodingErrorAction.REPORT)
            .decode(bytes);

    return chars.toString();
}
