	Count int    `json:"count"`
}

// Before: each helper reparses the same raw JSON.
func HandleRequestBefore(body []byte) error {
	if err := validateUser(body); err != nil {
		return err
	}
	if err := processItems(body); err != nil {
		return err
	}
	if err := auditRequest(body); err != nil {
		return err
	}
	return nil
}

func validateUser(body []byte) error {
	var p Payload
	if err := json.Unmarshal(body, &p); err != nil {
		return err
	}
	if p.UserID == "" || p.Email == "" {
		return fmt.Errorf("missing user fields")
	}
	return nil
}

func processItems(body []byte) error {
	var p Payload
	if err := json.Unmarshal(body, &p); err != nil {
		return err
	}
	for _, item := range p.Items {
		_ = item
	}
	return nil
}

func auditRequest(body []byte) error {
	var p Payload
	if err := json.Unmarshal(body, &p); err != nil {
		return err
	}
	for _, role := range p.Roles {
		_ = role
	}
	return nil
}

// After: parse once, pass the structured payload everywhere.
func HandleRequest(body []byte) error {
	var p Payload
	if err := json.Unmarshal(body, &p); err != nil {
		return err
	}

	if err := validateUserPayload(&p); err != nil {
		return err
	}
	if err := processItemsPayload(&p); err != nil {
		return err
	}
	if err := auditRequestPayload(&p); err != nil {
		return err
	}
	return nil
}

func validateUserPayload(p *Payload) error {
	if p.UserID == "" || p.Email == "" {
		return fmt.Errorf("missing user fields")
	}
	return nil
}

func processItemsPayload(p *Payload) error {
	for _, item := range p.Items {
		_ = item
	}
	return nil
}

func auditRequestPayload(p *Payload) error {
	for _, role := range p.Roles {
		_ = role
	}
	return nil
}
```

**Bottleneck**
- Repeated `json.Unmarshal(body, &p)` in multiple helper functions for the same request.
- JSON decoding is linear in payload size and allocates repeatedly, so doing it 3+ times is the avoidable hot path.

**Refactor**
- Unmarshal once at the request boundary.
- Pass `*Payload` (or a request-scoped struct) into downstream helpers.
- Keep helpers focused on business logic, not input decoding.

**Big-O**
- Let `n` = JSON payload size, `k` = number of helpers that currently unmarshal.
- Before:
  - Time: **O(k·n)** for decoding alone, plus helper work.
  - Space: **O(n)** per unmarshal transiently; repeated allocations increase GC pressure.
- After:
  - Time: **O(n)** for one decode, plus helper work.
  - Space: **O(n)** once for the parsed struct.

If each helper also scans some decoded fields, total cost becomes:
- Before: **O(k·n + work)**
- After: **O(n + work)**

**Rule of thumb**
- If the same body is unmarshalled 4 times, you are paying about 4x the JSON parsing cost per request.

