```go
// Before
func parseRecords(lines []string) []Record {
    records := make([]Record, 0, len(lines))
    for _, line := range lines {
        parts := strings.Split(line, ",") // allocates slice + substrings bookkeeping each iteration
        if len(parts) < 3 {
            continue
        }

        rec := Record{
            ID:   strings.TrimSpace(parts[0]),            // usually allocates
            Name: strings.ToLower(strings.TrimSpace(parts[1])), // allocates again
        }

        vals := make([]int, 0, len(parts)-2) // allocates every iteration
        for _, p := range parts[2:] {
            n, err := strconv.Atoi(strings.TrimSpace(p)) // trim may allocate
            if err != nil {
                continue
            }
            vals = append(vals, n)
        }
        rec.Values = vals
        records = append(records, rec)
    }
    return records
}
```

```go
// After
func parseRecords(lines []string) []Record {
    records := make([]Record, 0, len(lines))
    for _, line := range lines {
        var rec Record
        rec.Values = make([]int, 0, 8) // small default; grows only when needed

        field := 0
        start := 0
        valid := true

        for i := 0; i <= len(line); i++ {
            if i != len(line) && line[i] != ',' {
                continue
            }

            token := trimASCII(line[start:i])
            switch field {
            case 0:
                if token == "" {
                    valid = false
                }
                rec.ID = token
            case 1:
                rec.Name = asciiLower(token)
            default:
                if token != "" {
                    n, err := strconv.Atoi(token)
                    if err == nil {
                        rec.Values = append(rec.Values, n)
                    }
                }
            }

            field++
            start = i + 1
        }

        if valid && field >= 3 {
            records = append(records, rec)
        }
    }
    return records
}

func trimASCII(s string) string {
    start, end := 0, len(s)
    for start < end && (s[start] == ' ' || s[start] == '\t' || s[start] == '\n' || s[start] == '\r') {
        start++
    }
    for start < end && (s[end-1] == ' ' || s[end-1] == '\t' || s[end-1] == '\n' || s[end-1] == '\r') {
        end--
    }
    return s[start:end] // subslice of original string; no allocation
}

func asciiLower(s string) string {
    for i := 0; i < len(s); i++ {
        c := s[i]
        if 'A' <= c && c <= 'Z' {
            b := make([]byte, len(s))
            copy(b, s)
            b[i] = c + ('a' - 'A')
            for j := i + 1; j < len(s); j++ {
                if 'A' <= b[j] && b[j] <= 'Z' {
                    b[j] += 'a' - 'A'
                }
            }
            return string(b) // allocates only when conversion is actually needed
        }
    }
    return s // no allocation if already lowercase
}
```

Bottleneck: the hot loop was doing per-record `strings.Split`, repeated `TrimSpace`/`ToLower`, and `make([]int, ...)`. That creates short-lived slices/strings on every iteration and drives GC.

What changed:
- Replaced `strings.Split` with a single pass over the line.
- Replaced repeated trimming with slice-based `trimASCII`.
- Lowercase conversion now allocates only if uppercase bytes exist.
- Avoided creating a temporary `parts` slice entirely.
- Kept `Values` growth amortized instead of sizing from a temporary split result.

Complexity:
- Before: **O(total input bytes)** time, but with extra per-line work from split/trim/lower passes.
- After: **O(total input bytes)** time, with fewer full-string passes and less allocator/GC overhead.

Allocation behavior:
- Before: roughly **O(records + total fields)** temporary allocations, plus one temporary `[]string` and one `[]int` backing array per record.
- After: **O(records)** mandatory result allocations, with per-field temporaries eliminated; only `Values` backing storage and occasional lowercase copies remain.

If you want, I can also show a version that reuses the `[]int` backing arrays via `sync.Pool` for a handler-local benchmark-driven optimization.

