Use memoization around the repeated pure transformation so identical inputs are computed once per render cycle instead of N times.

```ts
type User = {
  id: string;
  name: string;
  role: string;
  lastSeenAt: string;
};

function expensiveFormatUser(user: User): string {
  // Example expensive work
  return `${user.name.toUpperCase()} • ${user.role} • ${new Date(user.lastSeenAt).toLocaleString()}`;
}

// Per-render cache
function createFormatUserMemo() {
  const cache = new Map<string, string>();

  return (user: User): string => {
    const key = `${user.id}|${user.name}|${user.role}|${user.lastSeenAt}`;

    const cached = cache.get(key);
    if (cached !== undefined) return cached;

    const result = expensiveFormatUser(user);
    cache.set(key, result);
    return result;
  };
}

function renderUsers(users: User[]) {
  const formatUser = createFormatUserMemo();

  return users.map(user => ({
    id: user.id,
    label: formatUser(user),
    tooltip: formatUser(user),
    searchText: formatUser(user),
  }));
}
```

If you’re in React, use `useMemo` to scope the cache to the render inputs:

